sys_script_include.script:
var XeroIntegrationUtils = Class.create();
XeroIntegrationUtils.prototype = {
    initialize: function() {},
    syncCompanyFromContact: function(contact) {

        var result = {
            company_sys_id: '',
            is_new_company: false
        };

        var address = this.getAddress(contact);
        var phones = this.getPhones(contact);

        var company = new GlideRecord('core_company');

        // Search by Xero Contact ID
        company.addQuery(
            'x_691473_spm_xer_0_u_xero_contact_id',
            contact.ContactID
        );

        company.query();

        if (company.next()) {

            this.updateCompany(
                company,
                contact,
                address,
                phones
            );

            company.update();

            result.company_sys_id =
                company.getUniqueValue();

            return result;
        }

        // Search by Company Name
        company = new GlideRecord('core_company');

        company.addQuery(
            'name',
            contact.Name
        );

        company.query();

        if (company.next()) {

            this.updateCompany(
                company,
                contact,
                address,
                phones
            );

            company.update();

            result.company_sys_id =
                company.getUniqueValue();

            return result;
        }

        // Create new company

        result.company_sys_id =
            this.createCompany(
                contact,
                address,
                phones
            );

        result.is_new_company = true;

        return result;
    },

    getAddress: function(contact) {

        var result = {
            street: '',
            city: '',
            state: '',
            postalCode: '',
            country: ''
        };

        if (!contact.Addresses) {
            return result;
        }

        for (var i = 0; i < contact.Addresses.length; i++) {

            var address = contact.Addresses[i];

            if (address.AddressType == 'STREET') {

                result.street = [
                    address.AddressLine1 || '',
                    address.AddressLine2 || '',
                    address.AddressLine3 || '',
                    address.AddressLine4 || ''
                ].join(' ').trim();

                result.city = address.City || '';
                result.state = address.Region || '';
                result.postalCode = address.PostalCode || '';
                result.country = address.Country || '';

                break;
            }
        }

        return result;
    },

    getPhones: function(contact) {

        var result = {
            phone: '',
            fax: ''
        };

        if (!contact.Phones) {
            return result;
        }

        for (var i = 0; i < contact.Phones.length; i++) {

            var currentPhone = contact.Phones[i];

            var formattedPhone =
                (currentPhone.PhoneAreaCode || '') +
                (currentPhone.PhoneNumber || '');

            if (
                (currentPhone.PhoneType == 'DEFAULT' ||
                    currentPhone.PhoneType == 'MOBILE') &&
                !result.phone
            ) {

                result.phone = formattedPhone;
            }

            if (currentPhone.PhoneType == 'FAX') {

                result.fax = formattedPhone;
            }
        }

        return result;
    },

    updateCompany: function(
        company,
        contact,
        address,
        phones
    ) {

        if (contact.EmailAddress) {

            company.setValue(
                'email',
                contact.EmailAddress
            );
        }

        if (phones.phone) {

            company.setValue(
                'phone',
                phones.phone
            );
        }

        if (phones.fax) {

            company.setValue(
                'fax_phone',
                phones.fax
            );
        }

        if (address.street) {

            company.setValue(
                'street',
                address.street
            );
        }

        if (address.city) {

            company.setValue(
                'city',
                address.city
            );
        }

        if (address.state) {

            company.setValue(
                'state',
                address.state
            );
        }

        if (address.postalCode) {

            company.setValue(
                'zip',
                address.postalCode
            );
        }

        if (address.country) {

            company.setValue(
                'country',
                address.country
            );
        }

        company.setValue(
            'customer',
            contact.IsCustomer
        );

        company.setValue(
            'xx_snc_spm_xero_i_0_xero_contact_id',
            contact.ContactID
        );
    },

    createCompany: function(
        contact,
        address,
        phones
    ) {

        var company =
            new GlideRecord('core_company');

        company.initialize();

        company.setValue(
            'name',
            contact.Name
        );

        this.updateCompany(
            company,
            contact,
            address,
            phones
        );

        return company.insert();
    },
    type: 'XeroIntegrationUtils'
};
